// Compute VZ date window (UTC-4). Runs at 02:00 UTC = 22:00 VZ of previous UTC-day
const now = new Date();
const vzNow = new Date(now.getTime() - 4 * 3600 * 1000);
const y = vzNow.getUTCFullYear();
const m = String(vzNow.getUTCMonth() + 1).padStart(2, '0');
const d = String(vzNow.getUTCDate()).padStart(2, '0');
const vzDate = `${y}-${m}-${d}`;
const startIso = `${vzDate}T04:00:00Z`;
const next = new Date(Date.UTC(y, vzNow.getUTCMonth(), vzNow.getUTCDate() + 1));
const ny = next.getUTCFullYear();
const nm = String(next.getUTCMonth() + 1).padStart(2, '0');
const nd = String(next.getUTCDate()).padStart(2, '0');
const endIso = `${ny}-${nm}-${nd}T04:00:00Z`;
const fmtDate = `${d}/${m}/${y}`;
return [{ json: { vzDate, startIso, endIso, fmtDate } }];

// Build WhatsApp markdown summary
const dateInfo = $('VZ date window').first().json;
const ordersRaw = $('Get orders today').first().json || [];
const cashRaw = $('Get cash today').first().json || [];
const delivsRaw = $('Get pending deliveries').first().json || [];
const rateRow = $input.first().json || {};
const tasa = rateRow.Bs != null ? parseFloat(rateRow.Bs) : null;

const orders = Array.isArray(ordersRaw) ? ordersRaw : [];
const cash = Array.isArray(cashRaw) ? cashRaw : [];
const delivs = Array.isArray(delivsRaw) ? delivsRaw : [];

// Count by status
const byStatus = orders.reduce((a, o) => { a[o.status] = (a[o.status]||0)+1; return a; }, {});
const nuevos = orders.length;
const enRuta = byStatus['en_ruta'] || 0;
const entregados = (byStatus['entregado'] || 0) + (byStatus['completado'] || 0);

// Cash by wallet
const sumBy = (w, field) => cash.filter(c => c.wallet === w && c.movement_type === 'ingreso').reduce((s, c) => s + parseFloat(c[field] || 0), 0);
const totalCashUsd = sumBy('cash_usd', 'amount');
const totalZelle = sumBy('zelle', 'amount');
const totalBs = sumBy('bolivares', 'amount');
const bsInUsd = tasa ? totalBs / tasa : 0;
const granTotal = totalCashUsd + totalZelle + bsInUsd;

const fmtUsd = v => '$' + (Math.round(v * 100) / 100).toFixed(2);
const fmtBs = v => 'Bs ' + (Math.round(v * 100) / 100).toLocaleString('es-VE');

// Deliveries list
let deliveriesList = 'Ninguno';
if (delivs.length) {
  const byRider = delivs.reduce((a, d) => { const k = d.rider_name || 'sin asignar'; (a[k] = a[k] || []).push(d); return a; }, {});
  deliveriesList = Object.entries(byRider).map(([rider, ds]) => {
    const lines = ds.map(d => `  - ${d.destination || 'N/A'} (${d.status})`).join('\n');
    return `_${rider}_:\n${lines}`;
  }).join('\n');
}

const tasaStr = tasa ? (Math.round(tasa * 100) / 100).toString() : '—';

const text = `📊 *Resumen del día - Primal*\n📅 ${dateInfo.fmtDate}\n\n💵 *CAJA*\nCash USD: ${fmtUsd(totalCashUsd)}\nZelle: ${fmtUsd(totalZelle)}\nBolívares: ${fmtBs(totalBs)} (≈ ${fmtUsd(bsInUsd)})\n💰 Total: ${fmtUsd(granTotal)}\n\n📦 *PEDIDOS HOY*\nNuevos: ${nuevos} | En ruta: ${enRuta} | Entregados: ${entregados}\n\n🏍️ *DELIVERIES PENDIENTES*\n${deliveriesList}\n\n💱 Tasa: Bs ${tasaStr}/USD`;

return [{ json: { text } }];

